function isAnagram(s, t) {
  if (s.length !== t.length) return false;
  const cnt = {};
  for (const ch of s) cnt[ch] = (cnt[ch] || 0) + 1;
  for (const ch of t) {
    if (!cnt[ch]) return false;
    cnt[ch]--;
  }
  return true;
}

tests:
if (isAnagram('anagram', 'nagaram') !== true) throw new Error('anagram');
if (isAnagram('rat', 'car') !== false) throw new Error('not anagram');
if (isAnagram('', '') !== true) throw new Error('empty');
if (isAnagram('a', 'ab') !== false) throw new Error('length mismatch');

