function majority(nums) {
  const m = new Map();
  let best = null, bestCount = 0;
  for (const x of nums) {
    const c = (m.get(x) || 0) + 1;
    m.set(x, c);
    if (c > bestCount) { bestCount = c; best = x; }
  }
  return best;
}

tests:
if (majority([3, 2, 3]) !== 3) throw new Error('basic');
if (majority([2, 2, 1, 1, 1, 2, 2]) !== 2) throw new Error('longer');
if (majority([1]) !== 1) throw new Error('single');

