function wordCount(text) {
  const freq = {};
  for (const w of text.split(/\s+/).filter(Boolean)) freq[w] = (freq[w] || 0) + 1;
  return freq;
}

tests:
if (JSON.stringify(wordCount('a b a')) !== JSON.stringify({ a: 2, b: 1 })) throw new Error('basic');
if (JSON.stringify(wordCount('')) !== JSON.stringify({})) throw new Error('empty');
if (wordCount('hi').hi !== 1) throw new Error('single');
if (wordCount('go go go').go !== 3) throw new Error('repeat');
